export type ModelsSubscriptionPlan = unknown & {
  /** AllowInstantPurchase when false: plan may still be public, but checkout is disabled until a sales-led flow exists. */
  allowInstantPurchase?: boolean;
  /**
     * AnnualPrepayDiscountPercent when set (1–100, interval must be month): yearly checkout uses price*12*(100-pct)/100.
     * @minimum 1
     * @maximum 100
     */
  annualPrepayDiscountPercent?: number;
  /**
     * AnnualPrepayPricePerMonth when set (minor units, interval month): yearly checkout uses this * 12 per year.
     * @minimum 1
     */
  annualPrepayPricePerMonth?: number;
  /** unique plan code like "starter", "professional" */
  code?: string;
  createdAt?: string;
  /** "RUB", "USD" */
  currency?: string;
  /** DisplayOrder is used for public plan lists (lower values first). */
  displayOrder?: number;
  /** feature flags */
  features?: ModelsSubscriptionPlanFeatures;
  id?: string;
  /** "month", "year" */
  interval?: string;
  isActive?: boolean;
  /** IsFree when true: plan is always free (price=0 by contract); UI shows "Free" instead of "Custom pricing".
  Distinct from enterprise (also price=0 but not free). Set by platform operator in plan constructor. */
  isFree?: boolean;
  /** IsPromoted marks the single catalog recommended plan (marketing + in-app pricing highlight). */
  isPromoted?: boolean;
  isPublic?: boolean;
  /** quota limits */
  limits?: ModelsSubscriptionPlanLimits;
  /** LimitsNegotiable maps limit keys to true when the catalog should show “by agreement” instead of a numeric cap. */
  limitsNegotiable?: ModelsSubscriptionPlanLimitsNegotiable;
  /** Primary display name (e.g. Russian on RU marketing) */
  name?: string;
  nameEn?: string;
  /** price in minor units (cents/kopeks) */
  price?: number;
  /** PricingModel determines how the price field is interpreted.
  Default: "per_unit".
    "per_unit" – price per subdivision per billing period; total = price * active_subdivisions
    "flat"     – fixed price per billing period (legacy; use only for grandfathered plans)
  enums: flat,per_unit */
  pricingModel?: ModelsSubscriptionPlanPricingModel;
  updatedAt?: string;
};

